rity":"flow"},{"type":"B_angle_to_A_planet","angle_english":"Descendant","angle_chinese":"下降","angle_chinese_traditional":"下降點","planet_english":"ImumCoeli","planet_chinese":"天底","planet_chinese_traditional":"天底","allow":150,"aspect_english":"Quincunx","aspect_chinese":"梅花相","aspect_chinese_traditional":"梅花相","orb":0.45513170000001,"deg":0,"min":27,"sec":18,"in_out":"0","aspect_type":"challenging","strength":0.551,"polarity":"friction"}],"scores":{"total_score":96.1,"score_breakdown":{"emotional":97,"attraction":97,"stability":93.5,"harmony":97}}}},"chart_description":{"summary":[{"target":"双人互动基调：高强度羁绊","description":"在这段关系里，你们很难对彼此保持中立，客观更是一种奢望。情绪的起伏与行动的节奏，仿佛被同一股神秘且强大的力量同时点燃，一方有所动静，另一方会瞬间感应并跟随，默契与冲突都来得同样猛烈。"},{"target":"双人互动基调：激烈冲突","description":"两人在核心价值、生活节奏与情感表达方式上的差异十分鲜明，几乎没有模糊的中间地带。你追求效率，他偏向从容；你习惯直抒胸臆，他偏爱含蓄表达。这些本质的不同让磨合成为必修课，需要投入额外的时间与耐心，才能找到彼此都舒适的相处频率。"},{"target":"双人互动基调：深刻情感联结","description":"你们的心情波动常常高度同步，一方情绪低落，另一方也会莫名感到沉重；一方心生欢喜，对方也会跟着轻松愉悦。就连安静不语的沉默，都带着浓厚的情绪线索，不用开口，就能感受到对方心底的波澜，这种情绪上的共振，是旁人难以理解的默契。"},{"target":"双人互动基调：长期发展潜力","description":"你们都不是只活在浪漫幻想里的人，更愿意花时间与精力，去经营现实层面的具体安排。从日常相处的细节，到未来生活的规划，都愿意脚踏实地去落实，而非只停留在口头的美好承诺，这份务实，是关系长久的重要基础。"},{"target":"双人互动基调：成长型关系","description":"在这段关系的相处过程中，你们常常会被迫面对自身尚未整合的部分。那些被刻意忽略的缺点、未曾处理的创伤、不成熟的处事方式，都会在彼此的碰撞中无所遁形，看似是关系带来的矛盾，实则是自我完善的必经之路。"},{"target":"双人互动基调：宿命缘分","description":"无论是初次相识的瞬间，还是互动初期的点滴相处，双方总能给彼此留下极其深刻的印象。这种印象无关好坏，却带着强烈的记忆点，哪怕时隔许久再想起，当时的画面、情绪与感受，依然清晰得仿佛就发生在昨天。"}],"houses":{"a_in_b":[{"target":"A盘太阳落入B盘第8宫","description":"A的太阳落入B的第八宫，把核心自我与意志带进亲密、共享资源与转化。A以喜欢以真诚的光芒设定节奏，也在提醒彼此占有或秘密容易制造情绪漩涡。只要以赤诚沟通与共同疗愈面对阴影，并记得期待被看见并获得肯定，就能让深情化作共同蜕变与丰盛的力量。"},{"target":"A盘月亮落入B盘第8宫","description":"A的月亮落入B的第八宫，把情绪本能与安全感带进亲密、共享资源与转化。A以用本能直觉回应环境，也在提醒彼此占有或秘密容易制造情绪漩涡。只要以赤诚沟通与共同疗愈面对阴影，并记得需要被包容并得到情绪回应，就能让深情化作共同蜕变与丰盛的力量。"},{"target":"A盘水星落入B盘第9宫","description":"A的水星落入B的第九宫，把思维沟通与信息节奏带进信念体系、远行与冒险。A以擅长用语言整理世界，也在提醒彼此理念差异可能演变成价值拉扯。只要以开放对话与旅程感维持同频，并记得需要对话顺畅与逻辑被尊重，就能彼此就能并肩拓宽视野与人生地图。"},{"target":"A盘金星落入B盘第9宫","description":"A的金星落入B的第九宫，把价值