rity":"flow"},{"type":"B_angle_to_A_planet","angle_english":"Descendant","angle_chinese":"下降","angle_chinese_traditional":"下降點","planet_english":"ImumCoeli","planet_chinese":"天底","planet_chinese_traditional":"天底","allow":150,"aspect_english":"Quincunx","aspect_chinese":"梅花相","aspect_chinese_traditional":"梅花相","orb":0.45513170000001,"deg":0,"min":27,"sec":18,"in_out":"0","aspect_type":"challenging","strength":0.551,"polarity":"friction"}],"scores":{"total_score":96.1,"score_breakdown":{"emotional":97,"attraction":97,"stability":93.5,"harmony":97}}}},"chart_description":{"summary":[{"target":"雙人互動基調：高強度羈絆","description":"在這段關係裡，你們很難對彼此保持中立，客觀更是一種奢望。情緒的起伏與行動的節奏，彷彿被同一股神祕且強大的力量同時點燃，一方有所動靜，另一方會瞬間感應並跟隨，默契與衝突都來得同樣猛烈。"},{"target":"雙人互動基調：激烈衝突","description":"兩人在核心價值、生活節奏與情感表達方式上的差異十分鮮明，幾乎沒有模糊的中間地帶。你追求效率，他偏向從容；你習慣直抒胸臆，他偏愛含蓄表達。這些本質的不同讓磨合成為必修課，需要投入額外的時間與耐心，才能找到彼此都舒適的相處頻率。"},{"target":"雙人互動基調：深刻情感聯結","description":"你們的心情波動常常高度同步，一方情緒低落，另一方也會莫名感到沉重；一方心生歡喜，對方也會跟著輕鬆愉悅。就連安靜不語的沉默，都帶著濃厚的情緒線索，不用開口，就能感受到對方心底的波瀾，這種情緒上的共振，是旁人難以理解的默契。"},{"target":"雙人互動基調：長期發展潛力","description":"你們都不是只活在浪漫幻想裡的人，更願意花時間與精力，去經營現實層面的具體安排。從日常相處的細節，到未來生活的規劃，都願意腳踏實地去落實，而非只停留在口頭的美好承諾，這份務實，是關係長久的重要基礎。"},{"target":"雙人互動基調：成長型關係","description":"在這段關係的相處過程中，你們常常會被迫面對自身尚未整合的部分。那些被刻意忽略的缺點、未曾處理的創傷、不成熟的處事方式，都會在彼此的碰撞中無所遁形，看似是關係帶來的矛盾，實則是自我完善的必經之路。"},{"target":"雙人互動基調：宿命緣分","description":"無論是初次相識的瞬間，還是互動初期的點滴相處，雙方總能給彼此留下極其深刻的印象。這種印象無關好壞，卻帶著強烈的記憶點，哪怕時隔許久再想起，當時的畫面、情緒與感受，依然清晰得彷彿就發生在昨天。"}],"houses":{"a_in_b":[{"target":"A盤太陽落入B盤第8宮","description":"A的太陽落入B的第八宮，把核心自我與意志帶進親密、共享資源與轉化。A以喜歡以真誠的光芒設定節奏，也在提醒彼此佔有或祕密容易製造情緒漩渦。只要以赤誠溝通與共同療愈面對陰影，並記得期待被看見並獲得肯定，就能讓深情化作共同蛻變與豐盛的力量。"},{"target":"A盤月亮落入B盤第8宮","description":"A的月亮落入B的第八宮，把情緒本能與安全感帶進親密、共享資源與轉化。A以用本能直覺回應環境，也在提醒彼此佔有或祕密容易製造情緒漩渦。只要以赤誠溝通與共同療愈面對陰影，並記得需要被包容並得到情緒回應，就能讓深情化作共同蛻變與豐盛的力量。"},{"target":"A盤水星落入B盤第9宮","description":"A的水星落入B的第九宮，把思維溝通與信息節奏帶進信念體系、遠行與冒險。A以擅長用語言整理世界，也在提醒彼此理念差異可能演變成價值拉扯。只要以開放對話與旅程感維持同頻，並記得需要對話順暢與邏輯被尊重，就能彼此就能並肩拓寬視野與人生地圖。"},{"target":"A盤金星落入B盤第9宮","description":"A的金星落入B的第九宮，把價值